// parseCommand parses a chat message into a Command if it starts with /
func parseCommand(message string) (*Command, bool) {
	message = strings.TrimSpace(message)
	if !strings.HasPrefix(message, "/") {
		return nil, false
	}

	// Remove the leading /
	message = message[1:]
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return nil, false
	}

	return &Command{
		Name:   strings.ToLower(parts[0]),
		Args:   parts[1:],
		RawMsg: message,
	}, true
}

// authenticateRequest extracts and validates the session token from the request.
// SECURITY: We do NOT trust client-provided role headers. The role is always
// looked up server-side from our user store based on the authenticated session.
func (s *GameServer) authenticateRequest(r *http.Request) (*User, error) {
	// Extract session token from Authorization header (Bearer token)
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, fmt.Errorf("missing Authorization header")
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
		return nil, fmt.Errorf("invalid Authorization header format, expected 'Bearer <token>'")
	}
	token := parts[1]

	if len(token) == 0 || len(token) > 256 {
		return nil, fmt.Errorf("invalid token length")
	}

	// Validate session server-side
	userID, valid := s.sessions.Validate(token)
	if !valid {
		return nil, fmt.Errorf("invalid or expired session")
	}

	// SECURITY: Look up the user and their role from the SERVER-SIDE store.
	// We NEVER use role information provided by the client.
	user, ok := s.users.GetByID(userID)
	if !ok {
		return nil, fmt.Errorf("user not found")
	}

	// Check if user is banned
	if user.Banned {
		if time.Now().Before(user.BanExpiry) {
			return nil, fmt.Errorf("user is banned until %s. Reason: %s",
				user.BanExpiry.Format(time.RFC3339), user.BanReason)
		}
		// Ban expired, clear it
		user.Banned = false
		user.BanReason = ""
		user.BanExpiry = time.Time{}
		s.users.Update(user)
	}

	return user, nil
}

// handleLogin authenticates a user and returns a session token
func (s *GameServer) handleLogin(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req struct {
		Username string `json:"username"`
		Password string `json:"password"`
	}

	if err := json.NewDecoder(http.MaxBytesReader(w, r.Body, 1024)).Decode(&req); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	if req.Username == "" || req.Password == "" {
		http.Error(w, "Username and password are required", http.StatusBadRequest)
		return
	}

	user, ok := s.users.GetByUsername(req.Username)
	if !ok {
		// Use constant-time comparison behavior - don't reveal whether user exists
		// We still hash to prevent timing attacks
		bcrypt.GenerateFromPassword([]byte(req.Password), bcrypt.DefaultCost)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.Password)); err != nil {
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if user.Banned && time.Now().Before(user.BanExpiry) {
		http.Error(w, fmt.Sprintf("Account is banned until %s. Reason: %s",
			user.BanExpiry.Format(time.RFC3339), user.BanReason), http.StatusForbidden)
		return
	}

	token, err := s.sessions.Create(user.ID)
	if err != nil {
		log.Printf("ERROR: Failed to create session: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	log.Printf("AUDIT: User '%s' logged in successfully", user.Username)

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{
		"token":    token,
		"username": user.Username,
	})
}

// handleChat processes chat messages and commands
func (s *GameServer) handleChat(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// SECURITY: Authenticate using server-side session validation.
	// The user's role is determined by the server, NOT by any client-provided header.
	//
	// WARNING: A previous design accepted role information from client headers
	// (e.g., X-User-Role). This is critically insecure because any client can
	// set arbitrary headers to escalate their privileges. Always determine
	// authorization server-side.
	user, err := s.authenticateRequest(r)
	if err != nil {
		log.Printf("AUTH FAILURE: %v (remote: %s)", err, r.RemoteAddr)
		http.Error(w, "Unauthorized: "+err.Error(), http.StatusUnauthorized)
		return
	}

	var req struct {
		Message string `json:"message"`
	}

	if err := json.NewDecoder(http.MaxBytesReader(w, r.Body, 4096)).Decode(&req); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	if len(req.Message) == 0 {
		http.Error(w, "Message cannot be empty", http.StatusBadRequest)
		return
	}

	if len(req.Message) > 500 {
		http.Error(w, "Message too long (max 500 characters)", http.StatusBadRequest)
		return
	}

	// Check if the message is a command
	cmd, isCommand := parseCommand(req.Message)
	if !isCommand {
		// Regular chat message
		log.Printf("CHAT [%s]: %s", user.Username, req.Message)
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(CommandResult{
			Success: true,
			Message: fmt.Sprintf("[%s]: %s", user.Username, req.Message),
		})
		return
	}

	// Look up the command handler
	handler, exists := s.commands[cmd.Name]
	if !exists {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(CommandResult{
			Success: false,
			Message: fmt.Sprintf("Unknown command: /%s. Type /help for available commands.", cmd.Name),
		})
		return
	}

	// SECURITY: Check permissions using the SERVER-SIDE role, not any client-provided value
	if !hasPermission(user.Role, handler.RequiredRole) {
		log.Printf("AUDIT: Permission denied - User '%s' (role: %s) attempted command '/%s' (requires: %s)",
			user.Username, user.Role, cmd.Name, handler.RequiredRole)
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusForbidden)
		json.NewEncoder(w).Encode(CommandResult{
			Success: false,
			Message: fmt.Sprintf("Permission denied. Command '/%s' requires role '%s' or higher.",
				cmd.Name, handler.RequiredRole),
		})
		return
	}

	// Execute the command
	result := handler.Handler(s, user, cmd.Args)

	w.Header().Set("Content-Type", "application/json")
	if !result.Success {
		w.WriteHeader(http.StatusBadRequest)
	}
	json.NewEncoder(w).Encode(result)
}

// handleLogout invalidates a session
func (s *GameServer) handleLogout(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	authHeader := r.Header.Get("Authorization")
	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) == 2 && strings.EqualFold(parts[0], "Bearer") {
		s.sessions.Delete(parts[1])
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"message": "Logged out"})
}

func main() {
	server := NewGameServer()

	mux := http.NewServeMux()
	mux.HandleFunc("/api/login", server.handleLogin)
	mux.HandleFunc("/api/chat", server.handleChat)
	mux.HandleFunc("/api/logout", server.handleLogout)

	httpServer := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Println("=== GAME SERVER SECURITY NOTES ===")
	log.Println("- User roles are determined SERVER-SIDE only")
	log.Println("- Client-provided role headers are IGNORED")
	log.Println("- All admin actions are audit-logged")
	log.Println("- Sessions use cryptographically random tokens")
	log.Println("==================================")
	log.Println()
	log.Println("Test accounts:")
	log.Println("  admin_user / admin_secure_pass_123 (admin)")
	log.Println("  mod_user / mod_secure_pass_456 (moderator)")
	log.Println("  player_one / player_pass_789 (player)")
	log.Println()
	log.Printf("Game server starting on %s", httpServer.Addr)

	if err := httpServer.ListenAndServe(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}